// Only the element is required; index and array are optional:
const numbers = [1, 2, 3, 4, 5];

numbers.some(n => n > 3);   // true  — 4 and 5 both pass
numbers.every(n => n > 0);  // true  — all elements are positive

const numbers = [1, 2, 3, 4, 5];

// some() — true if any element passes:
numbers.some(n => n > 3);    // true  (4 and 5 pass)
numbers.some(n => n > 10);   // false (no element passes)
numbers.some(n => n === 3);  // true  (3 passes)

// every() — true only if all elements pass:
numbers.every(n => n > 0);   // true  (all are positive)
numbers.every(n => n > 3);   // false (1, 2, 3 fail)
numbers.every(n => n < 10);  // true  (all are below 10)

// Works on arrays of objects:
const users = [
  { name: 'Alice', verified: true },
  { name: 'Bob',   verified: false },
  { name: 'Carol', verified: true },
];

users.some(u => !u.verified);   // true  — Bob is not verified
users.every(u => u.verified);   // false — Bob fails
users.every(u => u.name.length > 2); // true — all names > 2 chars

// some() stops at the first truthy result:
const data = [1, 2, 99, 4, 5];

// The callback is called for 1, 2, then 99 — stops there.
data.some(n => {
  console.log('checking', n);
  return n > 50;
});
// 'checking 1'
// 'checking 2'
// 'checking 99'  ← stops here, returns true

// every() stops at the first falsy result:
data.every(n => {
  console.log('checking', n);
  return n < 50;
});
// 'checking 1'
// 'checking 2'
// 'checking 99'  ← stops here, returns false

const tags = ['javascript', 'react', 'typescript'];

// Does the array contain a specific value?
const hasReact = tags.some(tag => tag === 'react'); // true

// Are all tags non-empty strings?
const allValid = tags.every(tag => tag.length > 0);  // true

// Does any tag start with 'type'?
tags.some(tag => tag.startsWith('type')); // true ('typescript')

const fields = [
  { name: 'email',    value: 'user@example.com', required: true },
  { name: 'username', value: 'alice',             required: true },
  { name: 'bio',      value: '',                  required: false },
];

// Is any required field empty?
const hasMissingRequired = fields.some(
  field => field.required && field.value.trim() === ''
);
// false — both required fields are filled

// Are all required fields filled?
const allRequiredFilled = fields
  .filter(f => f.required)
  .every(f => f.value.trim() !== '');
// true

const userRoles = ['viewer', 'editor'];
const adminRoles = ['admin', 'superadmin'];

// Does the user have any admin role?
const isAdmin = userRoles.some(role => adminRoles.includes(role));
