// Does the user have all required roles for an action?
const requiredRoles = ['viewer', 'editor'];
const canEditAll = requiredRoles.every(role => userRoles.includes(role));
// true

// Conditional rendering based on array state:
function NotificationBanner({ notifications }) {
  const hasUnread = notifications.some(n => !n.read);

  return (
    <div>
      {hasUnread && (
        <p className="banner">You have unread notifications.</p>
      )}
      <ul>
        {notifications.map(n => (
          <li key={n.id} className={n.read ? 'read' : 'unread'}>
            {n.message}
          </li>
        ))}
      </ul>
    </div>
  );
}

// Disabling a submit button until all fields are valid:
function SignupForm() {
  const [fields, setFields] = useState({
    username: '',
    email: '',
    password: '',
  });

  const allFilled = Object.values(fields).every(v => v.trim() !== '');

  function handleChange(e) {
    setFields(prev => ({ ...prev, [e.target.name]: e.target.value }));
  }

  return (
    <form>
      <input name="username" value={fields.username} onChange={handleChange} />
      <input name="email"    value={fields.email}    onChange={handleChange} />
      <input name="password" value={fields.password} onChange={handleChange} type="password" />
      {/* Button stays disabled until every field has a value */}
      <button type="submit" disabled={!allFilled}>Sign up</button>
    </form>
  );
}

// Status badge logic using some() and every():
function OrderSummary({ items }) {
  const allShipped  = items.every(item => item.status === 'shipped');
  const anyPending  = items.some(item => item.status === 'pending');

  const statusLabel = allShipped ? 'Fully shipped'
    : anyPending    ? 'Pending items'
    : 'Processing';

  return (
    <div>
      <span className="badge">{statusLabel}</span>
      {items.map(item => (
        <div key={item.id}>{item.name} — {item.status}</div>
      ))}
    </div>
  );
}
